CREATE OR REPLACE FUNCTION transition_task_status(p_task_id TEXT, p_new_status TEXT, p_user_id TEXT DEFAULT 'system', p_user_name TEXT DEFAULT '', p_force BOOLEAN DEFAULT false, p_blocked_reason TEXT DEFAULT NULL) RETURNS JSONB LANGUAGE plpgsql SECURITY DEFINER AS $$ DECLARE v_task RECORD; v_valid_transitions JSONB; v_allowed TEXT[]; v_now TIMESTAMPTZ := now(); v_local_date TEXT := to_char(v_now AT TIME ZONE 'America/Monterrey', 'YYYY-MM-DD'); BEGIN PERFORM set_config('app.allow_status_change', 'true', true); SELECT * INTO v_task FROM tasks WHERE id = p_task_id FOR UPDATE; IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'Task not found'); END IF; v_valid_transitions := '{"backlog":["pending","in_progress","cancelled"],"pending":["in_progress","blocked","cancelled"],"in_progress":["validation","blocked","completed","cancelled"],"validation":["in_progress","completed","blocked"],"blocked":["pending","in_progress"],"completed":["in_progress"],"cancelled":["backlog"]}'::jsonb; IF NOT p_force THEN SELECT array_agg(value::text) INTO v_allowed FROM jsonb_array_elements_text(COALESCE(v_valid_transitions -> v_task.status, '[]'::jsonb)); IF v_allowed IS NULL OR NOT (p_new_status = ANY(v_allowed)) THEN RETURN jsonb_build_object('success', false, 'error', format('Invalid transition: %s -> %s', v_task.status, p_new_status), 'currentStatus', v_task.status, 'allowedTransitions', COALESCE(v_valid_transitions -> v_task.status, '[]'::jsonb)); END IF; END IF; UPDATE tasks SET status = p_new_status, updated_at = v_now, completed_date = CASE WHEN p_new_status = 'completed' THEN to_char(v_now, 'YYYY-MM-DD"T"HH24:MI:SS"Z"') WHEN v_task.status = 'completed' AND p_new_status != 'completed' THEN NULL ELSE completed_date END, blocked_reason = CASE WHEN p_new_status = 'blocked' THEN COALESCE(p_blocked_reason, blocked_reason) WHEN v_task.status = 'blocked' AND p_new_status != 'blocked' THEN '' ELSE blocked_reason END, blocked_at = CASE WHEN p_new_status = 'blocked' THEN v_now ELSE blocked_at END, unblocked_at = CASE WHEN v_task.status = 'blocked' AND p_new_status != 'blocked' THEN v_now ELSE unblocked_at END WHERE id = p_task_id; INSERT INTO task_activity_log (task_id, type, description, user_id, user_name, "timestamp", date) VALUES (p_task_id, 'status_changed', format('Estado: %s -> %s', v_task.status, p_new_status), p_user_id, p_user_name, v_now, v_local_date); IF p_new_status = 'blocked' THEN INSERT INTO task_block_history (task_id, blocked_at, blocked_reason, blocked_by_user_id, blocked_by_name, assigned_to) VALUES (p_task_id, v_now, COALESCE(p_blocked_reason, ''), p_user_id, p_user_name, v_task.assigned_to); END IF; IF v_task.status = 'blocked' AND p_new_status != 'blocked' THEN UPDATE task_block_history SET unblocked_at = v_now, unblocked_by_user_id = p_user_id, duration_hours = EXTRACT(EPOCH FROM (v_now - blocked_at)) / 3600.0 WHERE task_id = p_task_id AND unblocked_at IS NULL; END IF; PERFORM set_config('app.allow_status_change', 'false', true); RETURN jsonb_build_object('success', true, 'previousStatus', v_task.status, 'newStatus', p_new_status, 'taskId', p_task_id); END; $$
